SELECT allocation_id, notes
FROM ip_allocations
WHERE unit_id = 0;

SELECT unit_id, COUNT(allocation_id) AS allocation_count
FROM ip_allocations
GROUP BY unit_id;

SELECT network_name, cidr, status
FROM ip_networks
WHERE status = 'active';

SELECT COUNT(*) AS active_network_count
FROM ip_networks
WHERE status = 'active';

SELECT ip_address
FROM ip_usage
WHERE subnet_id = 0;

SELECT status, COUNT(*) AS network_count
FROM ip_networks
GROUP BY status;
